function ie(i: number, e: number): string {
  let mm: string = ""
  for (let a: number = 0; a < i; a++) {
    for (let b: number = 0; b < e; b++) {
      if ((a + b) % 3 == 0) {
        mm = mm + "SAI"
      } else if ((a + b) % 3 == 1) {
        mm = mm + "KI"
      } else {
        mm = mm + "YOU"
      }
      mm = mm + "."
    }
    mm = mm + "\n"
  }
  return mm
}
